import{_ as t,a as e,b as d,c as r}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as n,o as c,c as p,a2 as h}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"النسخ الاحتياطي الزائد وتبديل مصدر القراءة","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/Other/redundant-backup-and-read-source.md","filePath":"ar-SA/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),u={name:"ar-SA/Other/redundant-backup-and-read-source.md"};function l(o,a,i,s,b,k){return c(),p("div",null,[...a[0]||(a[0]=[h('<h1 id="النسخ-الاحتياطي-الزائد-وتبديل-مصدر-القراءة" tabindex="-1">النسخ الاحتياطي الزائد وتبديل مصدر القراءة <a class="header-anchor" href="#النسخ-الاحتياطي-الزائد-وتبديل-مصدر-القراءة" aria-label="Permalink to &quot;النسخ الاحتياطي الزائد وتبديل مصدر القراءة&quot;">​</a></h1><p>يحفظ Redundant backup نسخة إضافية من ملف تم رفعه مسبقًا.</p><p>يمكن استخدام الملف الأساسي وملف النسخة الاحتياطية كمصادر قراءة. لن يلاحظ الزائر عادة أي فرق؛ الاختلاف الوحيد هو قناة التخزين التي تخدم الملف.</p><h2 id="ماذا-يستطيع-redundant-backup-فعله؟" tabindex="-1">ماذا يستطيع Redundant Backup فعله؟ <a class="header-anchor" href="#ماذا-يستطيع-redundant-backup-فعله؟" aria-label="Permalink to &quot;ماذا يستطيع Redundant Backup فعله؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الميزة</th><th>الوصف</th></tr></thead><tbody><tr><td>حفظ نسخة إضافية</td><td>نسخ الملفات احتياطيًا إلى قناة رفع أخرى لتقليل خطر تعطل قناة واحدة.</td></tr><tr><td>تبديل read source</td><td>بعد نجاح النسخ الاحتياطي، يمكن التبديل بين القناة الأساسية وقناة النسخة الاحتياطية للقراءة.</td></tr><tr><td>Single-file backup</td><td>نسخ ملف واحد احتياطيًا من صفحة تفاصيله.</td></tr><tr><td>Batch backup</td><td>اختيار عدة ملفات في لوحة الإدارة ونسخها معًا.</td></tr><tr><td>Global redundant backup</td><td>نسخ الملفات حسب المجلد من Other Settings.</td></tr></tbody></table><h2 id="مدخل-redundant-backup" tabindex="-1">مدخل Redundant Backup <a class="header-anchor" href="#مدخل-redundant-backup" aria-label="Permalink to &quot;مدخل Redundant Backup&quot;">​</a></h2><p>افتح:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+t+'" alt="Redundant backup" loading="lazy"></p><p>هذا المدخل مناسب لإضافة نسخ احتياطية لمجلد أو لكل الملفات دفعة واحدة.</p><p>يمكن اختيار backup channel يدويًا، أو اختيار automatic switching ليجد ImgBed قناة احتياطية مناسبة.</p><h2 id="النسخ-من-تفاصيل-الملف" tabindex="-1">النسخ من تفاصيل الملف <a class="header-anchor" href="#النسخ-من-تفاصيل-الملف" aria-label="Permalink to &quot;النسخ من تفاصيل الملف&quot;">​</a></h2><p>افتح صفحة تفاصيل ملف في لوحة الإدارة واضغط backup.</p><p><img src="'+e+'" alt="Backup في تفاصيل الملف" loading="lazy"></p><p>هذا مناسب لنسخ ملف مهم واحد عند الحاجة.</p><p>بعد نجاح النسخ تعرض صفحة تفاصيل الملف مصادر القراءة المتاحة.</p><h2 id="batch-backup-بالتحديد" tabindex="-1">Batch Backup بالتحديد <a class="header-anchor" href="#batch-backup-بالتحديد" aria-label="Permalink to &quot;Batch Backup بالتحديد&quot;">​</a></h2><p>في لوحة الإدارة، حدد عدة ملفات وشغّل batch backup.</p><p><img src="'+d+'" alt="Batch backup" loading="lazy"></p><p>هذا مناسب لمعالجة مجموعة ملفات.</p><p>Selection backup و file details backup و redundant backup ضمن Other Settings تستخدم النظام نفسه، لكنها مداخل مختلفة.</p><h2 id="تبديل-read-source-بعد-النسخ" tabindex="-1">تبديل Read Source بعد النسخ <a class="header-anchor" href="#تبديل-read-source-بعد-النسخ" aria-label="Permalink to &quot;تبديل Read Source بعد النسخ&quot;">​</a></h2><p>بعد اكتمال النسخ، تتيح صفحة تفاصيل الملف تبديل read source:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>الوصف</th></tr></thead><tbody><tr><td>Primary channel</td><td>القراءة من قناة الرفع الأصلية.</td></tr><tr><td>Backup channel</td><td>القراءة من قناة النسخة الاحتياطية.</td></tr></tbody></table><p><img src="'+r+'" alt="تبديل read source بعد النسخ" loading="lazy"></p><p>لا يحتاج الزوار إلى معرفة هل الملف يُخدم من القناة الأساسية أو الاحتياطية.</p><p>مصدر القراءة الذي تختاره يصبح المصدر المفضل للوصول اللاحق إلى الملف.</p><h2 id="متى-يتم-تجاوز-النسخ؟" tabindex="-1">متى يتم تجاوز النسخ؟ <a class="header-anchor" href="#متى-يتم-تجاوز-النسخ؟" aria-label="Permalink to &quot;متى يتم تجاوز النسخ؟&quot;">​</a></h2><p>الحالات التالية تُتجاوز أثناء النسخ وليست أخطاء:</p><table tabindex="0"><thead><tr><th>الحالة</th><th>سبب التجاوز</th></tr></thead><tbody><tr><td>Already backed up</td><td>الملف الذي لديه نسخة احتياطية لا يُنسخ مرة أخرى.</td></tr><tr><td>Primary and backup channels are the same</td><td>يجب أن تحفظ النسخة الاحتياطية في قناة أخرى حتى تكون مفيدة.</td></tr><tr><td>No usable backup channel</td><td>لا توجد قناة بديلة مناسبة.</td></tr></tbody></table><p>باختصار: يجب أن تذهب النسخ الاحتياطية إلى قناة أخرى، والملفات المنسوخة مسبقًا لا تستهلك مساحة إضافية مرة أخرى.</p><h2 id="primary-channel-و-backup-channel" tabindex="-1">Primary Channel و Backup Channel <a class="header-anchor" href="#primary-channel-و-backup-channel" aria-label="Permalink to &quot;Primary Channel و Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الاسم</th><th>المعنى</th></tr></thead><tbody><tr><td>Primary channel</td><td>القناة المستخدمة عند رفع الملف لأول مرة.</td></tr><tr><td>Backup channel</td><td>القناة التي تحفظ النسخة الزائدة.</td></tr><tr><td>Primary read source</td><td>الملف يُقرأ حاليًا من القناة الأساسية.</td></tr><tr><td>Backup read source</td><td>الملف يُقرأ حاليًا من قناة النسخة الاحتياطية.</td></tr></tbody></table><p>مصادر القراءة الأساسية والاحتياطية تقدم السلوك نفسه للمستخدم.</p><p>ما دام backup file متاحًا، تستمر الصور والفيديوهات وروابط التنزيل في العمل بعد التبديل إلى backup read source.</p><h2 id="ماذا-يحدث-عند-حذف-ملف؟" tabindex="-1">ماذا يحدث عند حذف ملف؟ <a class="header-anchor" href="#ماذا-يحدث-عند-حذف-ملف؟" aria-label="Permalink to &quot;ماذا يحدث عند حذف ملف؟&quot;">​</a></h2><p>عند حذف ملف، يحذف ImgBed الملف الأساسي وملف النسخة الاحتياطية معًا.</p>',37)])])}const y=n(u,[["render",l]]);export{g as __pageData,y as default};
